mapper.select:
/* 감사: 조건별 목록 (관리자 조회, 최신순) */ SELECT A.AUD_LOG_SN AS audLogSn, A.USR_SN AS usrSn, U.USR_NM AS usrNm, A.AUD_LOG_TYPE_CD AS audLogTypeCd, T.CMM_NM AS audLogTypeNm, A.AUD_LOG_REF_TYPE_CD AS audLogRefTypeCd, R.CMM_NM AS refTypeNm, A.AUD_LOG_REF_SN AS audLogRefSn, A.AUD_LOG_RSON_CN AS audLogRsonCn, A.AUD_LOG_IP_ADDR AS audLogIpAddr, A.AUD_LOG_REG_DT AS audLogRegDt FROM AUDIT_LOG A JOIN CMM_CODE T ON T.CMM_CD = A.AUD_LOG_TYPE_CD LEFT JOIN CMM_CODE R ON R.CMM_CD = A.AUD_LOG_REF_TYPE_CD LEFT JOIN USERS U ON U.USR_SN = A.USR_SN
AND A.USR_SN = #{usrSn} AND A.AUD_LOG_TYPE_CD = #{audLogTypeCd} AND A.AUD_LOG_REG_DT >= #{fromDt} AND A.AUD_LOG_REG_DT <= #{toDt}
ORDER BY A.AUD_LOG_SN DESC LIMIT #{limit}
